```cpp
void xoaChuso(char chr[MAX], int& start_idx) {
    int current_len = strlen(chr);
    if (start_idx + 1 >= current_len) return; // Không đủ 2 ký tự để xóa

    // Dịch chuyển các ký tự
    for (int i = start_idx; i < current_len - 2; ++i) {
        chr[i] = chr[i + 2];
    }
    // Gán null terminator ở độ dài mới
    chr[current_len - 2] = '\0';
}
```

