bool isDiagonalSymmetric(int matrix[][100], int n) {
    // Check main diagonal symmetry
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (matrix[i][j] != matrix[j][i]) {
                return false; // Returns false if not main diagonal symmetric
            }
        }
    }
    // Check anti-diagonal symmetry (only reached if main diagonal symmetric)
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (matrix[i][j] != matrix[n - j - 1][n - i - 1]) {
                return false; // Returns false if not anti-diagonal symmetric
            }
        }
    }
    return true; // Only reached if BOTH are symmetric
}

